class CryptoWallet: ObservableObject {
    @Published var privateKey: P256.Signing.PrivateKey?
    @Published var publicKey: P256.Signing.PublicKey?
    
    init() {
        loadKeys()
    }
    
    func generateKeys() {
        let key = P256.Signing.PrivateKey()
        self.privateKey = key
        self.publicKey = key.publicKey
        saveKeys(privateKey: key)
    }
    
    func saveKeys(privateKey: P256.Signing.PrivateKey) {
        let keyData = privateKey.rawRepresentation
        KeychainHelper.shared.save(data: keyData, service: "com.example.CryptoWallet", account: "privateKey")
    }
    
    func loadKeys() {
        guard let keyData = KeychainHelper.shared.read(service: "com.example.CryptoWallet", account: "privateKey") else {
            return
        }
        do {
            let key = try P256.Signing.PrivateKey(rawRepresentation: keyData)
            self.privateKey = key
            self.publicKey = key.publicKey
        } catch {
            print("Failed to load key from keychain: \(error)")
        }
    }
    
    func signTransaction(transactionData: Data) -> Data? {
        guard let privateKey = self.privateKey else { return nil }
        do {
            let signature = try privateKey.signature(for: transactionData)
            return signature.derRepresentation
        } catch {
            print("Signing failed: \(error)")
            return nil
        }
    }
    
    func sendTransaction(transaction: Transaction, completion: @escaping (Result<String, Error>) -> Void) {
        let encoder = JSONEncoder()
        guard let jsonData = try? encoder.encode(transaction) else {
            completion(.failure(NSError(domain: "EncodeError", code: 0, userInfo: nil)))
