class KeychainHelper {
    static let shared = KeychainHelper()
    
    func save(data: Data, service: String, account: String) {
        let query: [String: Any] = [
            kSecClass as String       : kSecClassGenericPassword,
            kSecAttrService as String : service,
            kSecAttrAccount as String : account,
            kSecValueData as String   : data
        ]
        
        SecItemDelete(query as CFDictionary)
        SecItemAdd(query as CFDictionary, nil)
    }
    
    func read(service: String, account: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String       : kSecClassGenericPassword,
            kSecAttrService as String : service,
            kSecAttrAccount as String : account,
            kSecReturnData as String  : true,
            kSecMatchLimit as String  : kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        if status == noErr {
            return result as? Data
        }
        return nil
    }
}

struct ContentView: View {
    @StateObject var wallet = CryptoWallet()
    @State private var transactionResponse: String = ""
    @State private var recipient: String = ""
    @State private var amount: String = ""
    
    var body: some View {
        NavigationView {
            VStack(spacing: 20) {
                if let publicKey = wallet.publicKey,
                   let compactKey = publicKey.compactRepresentation {
                    Text("Wallet Address:")
                        .font(.headline)
                    Text(compactKey.base64EncodedString())
                        .font(.subheadline)
                        .padding()
                } else {
                    Text("No wallet generated")
                        .padding()
                }
                
                Button("Generate Key Pair") {
                    wallet.generateKeys()
                }
                .padding()
                
                Divider()
                
                TextField("Recipient Address", text: $recipient)
                    .textFieldStyle(RoundedBorderTextFieldStyle())
                    .padding([.leading, .trailing])
                TextField("Amount", text: $amount)
                    .keyboardType(.decimalPad)
                    .textFieldStyle(RoundedBorderTextFieldStyle())
                    .padding([.leading, .trailing])
                
                Button("Send Transaction") {
                    processTransaction()
                }
                .padding()
                
                Text("Response:")
                    .font(.headline)
                Text(transactionResponse)
                    .multilineTextAlignment(.center)
                    .padding()
                
                Spacer()
            }
            .navigationTitle("Crypto Wallet")
        }
    }
    
    func processTransaction() {
        guard let amountValue = Double(amount) else { return }
        let senderAddress = wallet.publicKey?.compactRepresentation?.base64EncodedString() ?? ""
        var transaction = Transaction(sender: senderAddress, recipient: recipient, amount: amountValue, signature: nil)
        
        let encoder = JSONEncoder()
        guard let txData = try? encoder.encode(transaction),
              let signatureData = wallet.signTransaction(transactionData: txData) else {
            return
        }
        transaction.signature = signatureData.base64EncodedString()
        
        wallet.sendTransaction(transaction: transaction) { result in
            DispatchQueue.main.async {
                switch result {
                case .success(let response):
                    transactionResponse = response
                case .failure(let error):
                    transactionResponse = "Error: \(error.localizedDescription)"
                }
            }
        }
    }
}

